const fs=require('fs');
const cp=require('child_process');
const txt=fs.readFileSync('/app/sequences.fasta','utf8').trim();
const recs={};
for(const b of txt.split('>').filter(Boolean)){
  const lines=b.trim().split(/\r?\n/); recs[lines[0].trim()]=lines.slice(1).join('').trim().toLowerCase();
}
const inp=recs['input']; const out=recs['output'];
const site=215; const ins=out.slice(site,site+(out.length-inp.length));
function tm(seq){
  const cmd=`oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 ${seq}`;
  const o=cp.execSync(cmd,{encoding:'utf8'}).trim();
  return parseFloat(o);
}
function revcomp(s){return s.replace(/[acgt]/g,c=>({a:'t',c:'g',g:'c',t:'a'}[c])).split('').reverse().join('');}
const cands=[];
for(let lf=15;lf<=36;lf++){
  const af=inp.slice(site,site+lf);
  const tmf=tm(af);
  for(let lr=15;lr<=36;lr++){
    const ar=inp.slice(site-lr,site);
    const tmr=tm(ar);
    if(tmf>=58&&tmf<=72&&tmr>=58&&tmr<=72&&Math.abs(tmf-tmr)<=5){
      cands.push({lf,lr,tmf,tmr,af,ar,f:ins+af,r:revcomp(ar)});
    }
  }
}
console.log('insert',ins,'len',ins.length);
console.log('cands',cands.length);
// sort by |tm diff| then avg closeness to 65 then shortest total
cands.sort((a,b)=>Math.abs(a.tmf-a.tmr)-Math.abs(b.tmf-b.tmr)||Math.abs(((a.tmf+a.tmr)/2)-65)-Math.abs(((b.tmf+b.tmr)/2)-65)||((a.lf+a.lr)-(b.lf+b.lr)));
for(const c of cands.slice(0,25)){
  console.log(`lf ${c.lf} lr ${c.lr} tmf ${c.tmf.toFixed(2)} tmr ${c.tmr.toFixed(2)} diff ${Math.abs(c.tmf-c.tmr).toFixed(2)}`);
}
if(cands[0]){
  const c=cands[0];
  console.log('BEST');
  console.log('annealF',c.af);console.log('annealR_template',c.ar);console.log('F',c.f);console.log('R',c.r);
}
